mapper.select:
SELECT a.user_id, a.user_number, a.mch_id as mchId, a.user_phone, a.user_nike, b.nick, b.account_id, b.fans_count, b.region, b.status, b.update_time, b.level, b.id as memberAccountBindId, b.recertification_status as recertificationStatus FROM member a LEFT JOIN member_account_bind b ON a.user_id = b.user_id
a.user_phone is not null
AND b.channel_code = #{params.thirdPartyType}
AND a.user_phone like concat('%',#{params.mobile},'%')
AND b.account_id = #{params.thirdPartyAccount}
AND a.user_nike like concat('%',#{params.userNike},'%')
AND b.nick like concat('%',#{params.thirdPartyNick},'%')
AND b.status = #{params.status}
AND #{params.createTimeStart} <= b.create_time AND b.create_time < #{params.createTimeEnd}
order by b.create_time desc

SELECT a.user_id, a.user_number, a.user_phone, a.user_nike, a.mch_id as mchId, a.gmv,a.integral, a.user_level_id as userLevelId, b.update_time as updateTime, b.nick, b.account_id, b.fans_count, b.region, b.status, b.create_time, b.id as memberAccountBindId, c.level_name as levelName FROM member a LEFT JOIN member_account_bind b ON a.user_id = b.user_id LEFT JOIN member_integral_level c ON a.user_level_id = c.level
a.user_phone is not null AND b.status = 1
AND b.channel_code = #{params.thirdPartyType}
AND a.user_nike like concat('%',#{params.userNike},'%')
AND a.user_level_id = #{params.level}
AND a.user_phone like concat('%',#{params.mobile},'%')
AND a.mch_id = #{params.mchId}
AND #{params.createTimeStart} <= b.create_time AND b.create_time < #{params.createTimeEnd}
ORDER BY b.create_time DESC
